import{f as a,o as n,c as t,a2 as e}from"./chunks/framework.Ccw_j35p.js";const b=JSON.parse('{"title":"CAP 与 BASE","description":"","frontmatter":{"title":"CAP 与 BASE","outline":[2,3]},"headers":[],"relativePath":"middleware/distributed-system/cap-base.md","filePath":"middleware/distributed-system/cap-base.md","lastUpdated":1780747276000}'),i={name:"middleware/distributed-system/cap-base.md"};function r(l,s,p,d,o,h){return n(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="cap-与-base" tabindex="-1">CAP 与 BASE <a class="header-anchor" href="#cap-与-base" aria-label="Permalink to &quot;CAP 与 BASE&quot;">​</a></h1><blockquote><p>CAP 定理是分布式系统设计的&quot;第一性原理&quot;，BASE 理论则是互联网架构的实践哲学。理解这两者，是构建任何分布式系统的前提。</p></blockquote><h2 id="cap-定理深度解析" tabindex="-1">CAP 定理深度解析 <a class="header-anchor" href="#cap-定理深度解析" aria-label="Permalink to &quot;CAP 定理深度解析&quot;">​</a></h2><p>CAP 定理由 Eric Brewer 于 2000 年提出，后由 Gilbert 和 Lynch 在 2002 年给出形式化证明。它指出：<strong>一个分布式系统最多只能同时满足以下三个属性中的两个。</strong></p><h3 id="三要素的精确定义" tabindex="-1">三要素的精确定义 <a class="header-anchor" href="#三要素的精确定义" aria-label="Permalink to &quot;三要素的精确定义&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>精确定义</th><th>通俗理解</th></tr></thead><tbody><tr><td><strong>C (Consistency) — 一致性</strong></td><td>每次读操作都能读到最近一次写操作的结果（线性一致性）。所有节点在同一时刻看到的数据完全相同。</td><td>写入成功之后，任何人读到的一定是最新数据。</td></tr><tr><td><strong>A (Availability) — 可用性</strong></td><td>每一个非故障节点收到的请求，都必须在有限时间内返回一个非错误的响应。</td><td>系统永远能响应请求，不会返回错误。</td></tr><tr><td><strong>P (Partition Tolerance) — 分区容错性</strong></td><td>即使任意的网络分区导致节点间消息丢失，系统仍能继续正常运作。</td><td>网络断了，系统仍然能提供服务。</td></tr></tbody></table><h3 id="cap-的-二选二-误区" tabindex="-1">CAP 的&quot;二选二&quot;误区 <a class="header-anchor" href="#cap-的-二选二-误区" aria-label="Permalink to &quot;CAP 的&quot;二选二&quot;误区&quot;">​</a></h3><p>很多人误解 CAP 为&quot;只能三选二&quot;，这是不准确的。正确的理解是：</p><ul><li><strong>当网络没有分区时</strong>（正常运行），C 和 A 是可以同时满足的；</li><li><strong>当网络发生分区时</strong>，系统必须在 C 和 A 之间做出选择。</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>正常运行时:</span></span>
<span class="line"><span>   ┌──────────┐</span></span>
<span class="line"><span>   │   C + A  │  ← 网络畅通时，一致性、可用性可以兼得</span></span>
<span class="line"><span>   └──────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>网络分区时:</span></span>
<span class="line"><span>   ┌──────────┐         ┌──────────┐</span></span>
<span class="line"><span>   │  CP 模式  │   OR    │  AP 模式  │</span></span>
<span class="line"><span>   │ 保一致性   │         │ 保可用性   │</span></span>
<span class="line"><span>   │ 牺牲可用性 │         │ 容忍不一致 │</span></span>
<span class="line"><span>   └──────────┘         └──────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>由于网络分区在现实世界中<strong>无法避免</strong>（交换机故障、光纤被挖断、网络拥塞），所以 P 实际上是不能放弃的。因此，CAP 在实际工程中的真正选择是：<strong>当发生网络分区时，你选择 CP 还是 AP？</strong></p><h3 id="cp-vs-ap-的本质选择" tabindex="-1">CP vs AP 的本质选择 <a class="header-anchor" href="#cp-vs-ap-的本质选择" aria-label="Permalink to &quot;CP vs AP 的本质选择&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>CP 系统</th><th>AP 系统</th></tr></thead><tbody><tr><td><strong>核心取舍</strong></td><td>发生分区时，宁可不可用也要保证数据一致</td><td>发生分区时，宁可数据不一致也要保证可用</td></tr><tr><td><strong>写操作行为</strong></td><td>分区期间可能拒绝写入</td><td>分区期间继续接受写入，事后解决冲突</td></tr><tr><td><strong>读操作行为</strong></td><td>返回的一定是最新值</td><td>可能返回过期的旧值</td></tr><tr><td><strong>典型场景</strong></td><td>金融交易、库存扣减、账户余额</td><td>社交动态、商品浏览、CDN 内容分发</td></tr><tr><td><strong>恢复复杂度</strong></td><td>较低（没有冲突需要解决）</td><td>较高（需要冲突检测和合并策略）</td></tr></tbody></table><h3 id="各中间件的-cap-定位映射表" tabindex="-1">各中间件的 CAP 定位映射表 <a class="header-anchor" href="#各中间件的-cap-定位映射表" aria-label="Permalink to &quot;各中间件的 CAP 定位映射表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>中间件 / 系统</th><th>CAP 定位</th><th>说明</th></tr></thead><tbody><tr><td><strong>ZooKeeper</strong></td><td>CP</td><td>领导者选举期间集群不可用，但保证数据绝对一致</td></tr><tr><td><strong>etcd</strong></td><td>CP</td><td>基于 Raft，任何时刻只有一个 Leader 处理写入</td></tr><tr><td><strong>Consul</strong></td><td>CP (默认) / AP (可配)</td><td>默认强一致，也提供最终一致性模式</td></tr><tr><td><strong>Eureka</strong></td><td>AP</td><td>优先保证服务注册的可用性，允许短暂的不一致</td></tr><tr><td><strong>Nacos</strong></td><td>CP + AP 可切换</td><td>支持 AP 模式（临时实例）和 CP 模式（持久实例）</td></tr><tr><td><strong>Redis Cluster</strong></td><td>AP (默认)</td><td>主从异步复制，故障转移期间可能丢失数据</td></tr><tr><td><strong>MySQL 主从</strong></td><td>AP (异步复制)</td><td>主从复制延迟导致读到旧数据</td></tr><tr><td><strong>MongoDB (副本集)</strong></td><td>CP (多数写关注)</td><td>设置 writeConcern: majority 时达到 CP</td></tr><tr><td><strong>Kafka</strong></td><td>AP (默认) / CP (可配)</td><td>acks=all + min.insync.replicas 可接近 CP</td></tr><tr><td><strong>Cassandra</strong></td><td>AP (可调)</td><td>通过一致性级别（QUORUM / ALL）在 CAP 之间调节</td></tr></tbody></table><hr><h2 id="base-理论" tabindex="-1">BASE 理论 <a class="header-anchor" href="#base-理论" aria-label="Permalink to &quot;BASE 理论&quot;">​</a></h2><p>BASE 理论是对 CAP 定理中 AP 方案的一种实践性补充。它由 eBay 架构师 Dan Pritchett 提出，核心思想是：<strong>即使无法做到强一致性，系统也可以通过适当方式达到最终一致性。</strong></p><h3 id="ba-soft-state-eventually-consistent-详解" tabindex="-1">BA / Soft State / Eventually Consistent 详解 <a class="header-anchor" href="#ba-soft-state-eventually-consistent-详解" aria-label="Permalink to &quot;BA / Soft State / Eventually Consistent 详解&quot;">​</a></h3><table tabindex="0"><thead><tr><th>缩写</th><th>全称</th><th>含义</th></tr></thead><tbody><tr><td><strong>BA</strong></td><td>Basically Available</td><td><strong>基本可用</strong>：系统出现故障时允许损失部分可用性，但不等于系统不可用。例如响应时间变长（从 50ms 到 500ms），或者引导用户到降级页面。</td></tr><tr><td><strong>S</strong></td><td>Soft State</td><td><strong>软状态</strong>：系统中的数据存在中间状态，且该中间状态不会影响系统的整体可用性。允许不同节点的数据副本之间存在短暂的不一致。</td></tr><tr><td><strong>E</strong></td><td>Eventually Consistent</td><td><strong>最终一致性</strong>：不保证在任意时刻数据强一致，但保证在没有新的更新之后，经过一段时间的同步，所有副本最终会达到一致状态。</td></tr></tbody></table><p>BASE 理论诞生的背景是：传统的 ACID 事务在大型分布式系统中代价极高，而互联网场景（如社交、电商浏览）往往<strong>不需要实时强一致性</strong>。与其为了一个代价高昂的强一致性事务阻塞整个系统，不如&quot;最终一致&quot;。</p><h3 id="base-vs-acid-对比" tabindex="-1">BASE vs ACID 对比 <a class="header-anchor" href="#base-vs-acid-对比" aria-label="Permalink to &quot;BASE vs ACID 对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>ACID</th><th>BASE</th></tr></thead><tbody><tr><td><strong>思想倾向</strong></td><td>悲观，假设冲突频繁发生</td><td>乐观，假设冲突不会频繁发生</td></tr><tr><td><strong>一致性强度</strong></td><td>强一致性（写入立即可见）</td><td>最终一致性（写入后一段时间才可见）</td></tr><tr><td><strong>可用性</strong></td><td>为保证一致性可能牺牲可用性</td><td>优先保证可用性</td></tr><tr><td><strong>事务模型</strong></td><td>原子操作</td><td>柔性事务 + 补偿机制</td></tr><tr><td><strong>实现机制</strong></td><td>锁机制、MVCC、WAL</td><td>异步复制、版本向量、冲突解决</td></tr><tr><td><strong>适用场景</strong></td><td>银行转账、电商下单、账户扣减</td><td>社交动态、搜索引擎索引、缓存同步</td></tr><tr><td><strong>典型代表</strong></td><td>关系型数据库（MySQL / PostgreSQL）</td><td>NoSQL 数据库（Cassandra / DynamoDB / Redis）</td></tr><tr><td><strong>复杂性</strong></td><td>使用简单，业务逻辑清晰</td><td>需要额外处理不一致、冲突和重试</td></tr></tbody></table><h3 id="为什么分布式系统需要-base" tabindex="-1">为什么分布式系统需要 BASE <a class="header-anchor" href="#为什么分布式系统需要-base" aria-label="Permalink to &quot;为什么分布式系统需要 BASE&quot;">​</a></h3><p>在一个由成百上千台机器组成的分布式系统中，ACID 的强一致性会带来以下问题：</p><ol><li><strong>性能瓶颈</strong>：两阶段提交（2PC）等强一致性协议需要多轮网络往返，吞吐量随节点数增加而急剧下降；</li><li><strong>可用性牺牲</strong>：一旦发生分区，CP 系统会拒绝写入，这在 C 端互联网场景不可接受；</li><li><strong>可扩展性受限</strong>：锁竞争和同步等待使得水平扩展的收益递减。</li></ol><p>BASE 理论本质上是对 CAP 定理中 AP 路径的工程化落地——它承认不一致的现实，但通过版本向量（Vector Clock）、读修复（Read Repair）、反熵（Anti-Entropy）等机制，在<strong>不牺牲可用性</strong>的前提下，尽量缩小不一致的窗口期。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ACID 思维：                    BASE 思维：</span></span>
<span class="line"><span>┌─────────────────┐            ┌─────────────────────────┐</span></span>
<span class="line"><span>│   立即一致         │            │  副本1: v=1             │</span></span>
<span class="line"><span>│   所有节点同一时刻  │            │  副本2: v=0（短暂不一致）│</span></span>
<span class="line"><span>│   view 相同        │            │  副本3: v=1             │</span></span>
<span class="line"><span>│                   │            │           ↓             │</span></span>
<span class="line"><span>│   （代价：可用性）  │            │  最终全部 → v=1         │</span></span>
<span class="line"><span>└─────────────────┘            └─────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><hr><h2 id="分布式一致性模型" tabindex="-1">分布式一致性模型 <a class="header-anchor" href="#分布式一致性模型" aria-label="Permalink to &quot;分布式一致性模型&quot;">​</a></h2><p>一致性模型定义了系统对外提供的&quot;可见性保证&quot;——即一个写入操作在什么时间点、以什么顺序、被哪些客户端看到。</p><h3 id="六种一致性模型详解" tabindex="-1">六种一致性模型详解 <a class="header-anchor" href="#六种一致性模型详解" aria-label="Permalink to &quot;六种一致性模型详解&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th>定义</th><th>严格程度</th><th>典型系统</th></tr></thead><tbody><tr><td><strong>线性一致性 (Linearizability)</strong></td><td>最强模型。所有操作看起来都是<strong>原子地</strong>在某个时间点瞬间完成的，且操作顺序与<strong>真实时间顺序</strong>一致。</td><td>★★★★★</td><td>etcd、ZooKeeper (写)、Consul (CP)</td></tr><tr><td><strong>顺序一致性 (Sequential Consistency)</strong></td><td>所有操作按照某个全局顺序执行，但该顺序不必与真实时间一致。每个节点看到的顺序相同即可。</td><td>★★★★☆</td><td>ZooKeeper (全局)</td></tr><tr><td><strong>因果一致性 (Causal Consistency)</strong></td><td>具有因果关系的操作在所有节点上按因果顺序看到；无因果关系的操作可以以任意顺序出现。</td><td>★★★☆☆</td><td>MongoDB (causally consistent session)</td></tr><tr><td><strong>最终一致性 (Eventual Consistency)</strong></td><td>如果没有新的更新，最终所有副本都会收敛到相同值。</td><td>★★☆☆☆</td><td>DNS、Cassandra (默认)</td></tr><tr><td><strong>读写一致性 (Read-Your-Writes)</strong></td><td>客户端自己写入的数据，自己一定能读到最新版本。</td><td>★★★☆☆</td><td>MongoDB (readConcern: majority)</td></tr><tr><td><strong>单调读一致性 (Monotonic Reads)</strong></td><td>客户端不会&quot;时光倒流&quot;——一旦读到某个版本，后续读取不会返回更旧的版本。</td><td>★★★☆☆</td><td>DynamoDB、Cassandra (可配)</td></tr></tbody></table><h3 id="一致性模型强度对比" tabindex="-1">一致性模型强度对比 <a class="header-anchor" href="#一致性模型强度对比" aria-label="Permalink to &quot;一致性模型强度对比&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>严格 ◄────────────────────────────────────────────► 宽松</span></span>
<span class="line"><span></span></span>
<span class="line"><span>线性一致性    顺序一致性    因果一致性    读写一致性    单调读    最终一致性</span></span>
<span class="line"><span>   │              │              │             │           │          │</span></span>
<span class="line"><span>   └── 全局实时 ──┘              │             │           │          │</span></span>
<span class="line"><span>                  └── 全局顺序 ──┘             │           │          │</span></span>
<span class="line"><span>                                 └── 因果约束 ─┘───────────┘          │</span></span>
<span class="line"><span>                                                                      │</span></span>
<span class="line"><span>                                                     └── 最终收敛 ────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="模型之间蕴含关系" tabindex="-1">模型之间蕴含关系 <a class="header-anchor" href="#模型之间蕴含关系" aria-label="Permalink to &quot;模型之间蕴含关系&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>线性一致性 ⇒ 顺序一致性 ⇒ 因果一致性</span></span>
<span class="line"><span>                        ⇒ 读写一致性</span></span>
<span class="line"><span>                        ⇒ 单调读一致性</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>线性一致性是最强的保证，包含了下层所有模型的保证。但代价也最高——它要求每次操作需要多数派确认，增加了延迟和资源消耗。</p><hr><h2 id="经典高频面试题" tabindex="-1">经典高频面试题 <a class="header-anchor" href="#经典高频面试题" aria-label="Permalink to &quot;经典高频面试题&quot;">​</a></h2><h3 id="q1-cap-定理中-为什么不能同时满足三者-请用具体场景说明。" tabindex="-1">Q1: CAP 定理中，为什么不能同时满足三者？请用具体场景说明。 <a class="header-anchor" href="#q1-cap-定理中-为什么不能同时满足三者-请用具体场景说明。" aria-label="Permalink to &quot;Q1: CAP 定理中，为什么不能同时满足三者？请用具体场景说明。&quot;">​</a></h3><p><strong>答案：</strong></p><p>CAP 定理的核心矛盾在于：<strong>网络分区（P）发生是无法避免的客观事实，而一致性与可用性在分区期间是相互冲突的。</strong></p><p>我们用一个具体的银行转账场景来说明。</p><p><strong>场景设定</strong>：有一个双节点的分布式存储系统，节点 A 和节点 B 存储相同的账户余额数据。初始余额为 100 元。</p><p><strong>网络分区发生</strong>：A 和 B 之间的网络断开（交换机故障 / 光缆被挖断），但两个节点都在运行，也都能接收客户端请求。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  ┌──────────────┐                              ┌──────────────┐</span></span>
<span class="line"><span>  │    Client1   │                              │    Client2   │</span></span>
<span class="line"><span>  └──────┬───────┘                              └──────┬───────┘</span></span>
<span class="line"><span>         │ 写入 x=50                                  │ 读取 x</span></span>
<span class="line"><span>         ▼                                            ▼</span></span>
<span class="line"><span>  ┌──────────────┐       网络不通        ┌──────────────┐</span></span>
<span class="line"><span>  │   节点 A      │ ◄──── X ────────►     │   节点 B      │</span></span>
<span class="line"><span>  │   x = 50     │                       │   x = 100    │</span></span>
<span class="line"><span>  └──────────────┘                       └──────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>现在 Client1 向节点 A 写入 <code>x = 50</code>，Client2 向节点 B 读取 <code>x</code> 的值。</p><p><strong>如果选择一致性（CP）</strong>：</p><ul><li>节点 A 无法将写入同步到节点 B（网络不通），所以节点 A 必须<strong>拒绝写入</strong>或返回错误；</li><li>此时可用性被牺牲——写入请求虽然到达了正常运行的节点，但收到了错误响应。</li></ul><p><strong>如果选择可用性（AP）</strong>：</p><ul><li>节点 A 接受写入 <code>x = 50</code>，返回成功——可用性得到保证；</li><li>Client2 从节点 B 读取到 <code>x = 100</code>（旧值），与前一个写入不一致——一致性被破坏；</li><li>分区恢复后，需要通过冲突解决机制来让两个节点最终达成一致。</li></ul><p><strong>为什么不能三者同时满足？</strong></p><p>因为在分区期间，以下三个条件不可能同时成立：</p><ol><li><strong>分区在发生</strong>（P 条件成立：网络不通）；</li><li><strong>节点 A 写入成功</strong>（A 条件成立：节点正常响应）；</li><li><strong>节点 B 读到最新值</strong>（C 条件成立：所有节点数据一致）。</li></ol><p>条件 2 和条件 3 同时满足的前提是&quot;节点 A 能通知节点 B&quot;，但这被条件 1 阻止了。因此你想要 C 和 A，就必须牺牲 P，而 P 通常在现实中是<strong>无法被消除的</strong>（网络故障是物理现实），所以真正的决策只能是&quot;分区时选 C 还是选 A&quot;。</p><div class="tip custom-block"><p class="custom-block-title">通俗比喻</p><p>当你无法同时和两个人通电话时（网络分区），你只能选择跟一个人保持通话（可用性），但另一个人就会不知道你说了什么（一致性丢失）；或者你干脆挂断电话等网络恢复（牺牲可用性保证一致性）。</p></div><hr><h3 id="q2-base-理论和-acid-有什么区别-分别适用于什么场景" tabindex="-1">Q2: BASE 理论和 ACID 有什么区别？分别适用于什么场景？ <a class="header-anchor" href="#q2-base-理论和-acid-有什么区别-分别适用于什么场景" aria-label="Permalink to &quot;Q2: BASE 理论和 ACID 有什么区别？分别适用于什么场景？&quot;">​</a></h3><p><strong>答案：</strong></p><p><strong>本质区别：思想哲学不同</strong></p><p>ACID 是<strong>悲观主义</strong>——假设冲突一定会发生，因此每个操作都必须严格保证原子性和隔离性。它的设计目标是让并发事务之间看起来像是串行执行一样，用户完全不用担心并发问题。</p><p>BASE 是<strong>乐观主义</strong>——假设冲突不会频繁发生，即使发生了也可以通过事后补偿来解决。它的设计目标是最大化可用性和吞吐量，容忍短暂的不一致，关注最终结果的正确性。</p><p><strong>ACID（数据库事务的黄金标准）</strong>：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- ACID 事务模型（以银行转账为例）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">BEGIN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TRANSACTION</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    UPDATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> accounts </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> balance </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> balance </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;A&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- A 扣款</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    UPDATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> accounts </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> balance </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> balance </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;B&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- B 入账</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COMMIT</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 如果任何一步失败 → 全部回滚</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 并发事务隔离 → 其他人看不到中间状态</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 提交后持久化 → 即使宕机也不会丢</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p><strong>ACID 适用场景</strong>：</p><ul><li>金融交易系统（转账、支付、清算）</li><li>电商核心下单链路（库存扣减、优惠券核销、订单生成）</li><li>账户余额管理</li><li>任何&quot;数据错了比系统慢了更严重&quot;的场景</li></ul><p><strong>BASE（互联网架构的实践哲学）</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BASE 事务模型（以电商商品浏览为例）：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>节点 A：库存显示 10 件</span></span>
<span class="line"><span>节点 B：库存显示 8 件（刚刚有人下单，但尚未同步到 A）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>用户看到 10 件 → 下单 → 实际库存只剩 8 件 → 订单确认时提示&quot;库存不足&quot;</span></span>
<span class="line"><span>→ 柔性补偿：退款 + 发放优惠券 → 用户体验可接受</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果为了强一致而加锁：</span></span>
<span class="line"><span>所有浏览库存的请求都必须从唯一主库读取 → 读性能成为瓶颈</span></span>
<span class="line"><span>→ 大促时系统崩溃 → 损失更大</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p><strong>BASE 适用场景</strong>：</p><ul><li>社交平台动态流（发了一条动态，朋友延迟几秒看到完全可接受）</li><li>搜索引擎索引更新（网页更新后，搜索索引几分钟后才刷新）</li><li>推荐系统、广告投放</li><li>电商商品浏览和搜索（非下单核心链路的读场景）</li><li>监控与日志系统</li><li>任何&quot;可用性 &gt; 强一致性&quot;的场景</li></ul><p><strong>核心对比总结</strong>：</p><table tabindex="0"><thead><tr><th></th><th>ACID</th><th>BASE</th></tr></thead><tbody><tr><td><strong>核心目标</strong></td><td>保证数据绝对正确</td><td>保证系统始终可用</td></tr><tr><td><strong>牺牲项</strong></td><td>性能和可用性</td><td>强一致性</td></tr><tr><td><strong>冲突处理</strong></td><td>事前预防（锁 / MVCC）</td><td>事后补偿（Saga / TCC / 重试）</td></tr><tr><td><strong>复杂度</strong></td><td>业务逻辑简单，基础设施复杂</td><td>基础设施简单，业务逻辑复杂</td></tr><tr><td><strong>可扩展性</strong></td><td>受限（分布式事务协调开销大）</td><td>可以水平扩展</td></tr></tbody></table><p><strong>实际架构中的综合使用</strong>：</p><p>现代大型系统通常不是非此即彼，而是 <strong>ACID + BASE 混合使用</strong>：</p><ul><li>核心交易链路用 ACID（MySQL 单机事务 + 最终一致性补偿）；</li><li>读多写少的查询场景用 BASE（Redis 缓存 + MySQL 异步同步）；</li><li>跨服务的分布式事务用 Saga 模式（本质是 BASE 的工程实现）。</li></ul><div class="warning custom-block"><p class="custom-block-title">关键心得</p><p>不要试图在全系统范围内追求 ACID 强一致性。识别出真正需要 ACID 的核心链路，其余部分用 BASE 思想来设计，这是分布式系统架构师的基本功。</p></div>`,77)])])}const g=a(i,[["render",r]]);export{b as __pageData,g as default};
